import React from 'react' import { Navigate, Route, Routes } from 'react-router-dom' import LandingPage from './pages/LandingPage' import LoginPage from './pages/LoginPage' import RegisterPage from './pages/RegisterPage' import ProductsPage from './pages/ProductsPage' import UserProfilePage from './pages/UserProfilePage' import './App.css'
function App() { return ( <Routes> <Route path="/" element={<LandingPage />} /> <Route path="/products" element={<ProductsPage />} /> <Route path="/login" element={<LoginPage />} /> <Route path="/register" element={<RegisterPage />} /> <Route path="/me" element={<UserProfilePage />} /> <Route path="*" element={<Navigate to="/" replace />} /> </Routes> ) }
